import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { Menu, X, Instagram, Facebook } from 'lucide-react';

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);

  const menuItems = [
    { title: 'Home', path: '/' },
    { title: 'Academy', path: '/academy' },
    { title: 'Pro Services', path: '/pro-services' },
    { title: 'Our Story', path: '/story' },
    { title: 'Connect', path: '/connect' },
  ];

  return (
    <nav className="fixed w-full z-50 bg-charcoal/80 backdrop-blur-md border-b border-gold/20">
      <div className="max-w-7xl mx-auto px-6 lg:px-12">
        <div className="flex justify-between items-center h-20">
          <Link to="/" className="flex items-center space-x-2">
            <span className="text-2xl font-cinzel font-bold tracking-[0.2em] text-gold-gradient">DOD</span>
          </Link>

          {/* Desktop Menu */}
          <div className="hidden md:flex space-x-8">
            {menuItems.map((item) => (
              <Link
                key={item.path}
                to={item.path}
                className="text-sm font-montserrat uppercase tracking-widest hover:text-gold transition-colors duration-300"
              >
                {item.title}
              </Link>
            ))}
          </div>

          <div className="hidden md:flex items-center space-x-4">
            <Instagram className="w-5 h-5 text-gold cursor-pointer" />
            <Facebook className="w-5 h-5 text-gold cursor-pointer" />
          </div>

          {/* Mobile Toggle */}
          <button className="md:hidden text-gold" onClick={() => setIsOpen(!isOpen)}>
            {isOpen ? <X size={28} /> : <Menu size={28} />}
          </button>
        </div>
      </div>

      {/* Mobile Drawer */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, x: '100%' }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: '100%' }}
            transition={{ type: 'spring', damping: 25, stiffness: 200 }}
            className="fixed inset-0 top-20 bg-charcoal z-40 flex flex-col items-center justify-center space-y-8"
          >
            {menuItems.map((item) => (
              <Link
                key={item.path}
                to={item.path}
                onClick={() => setIsOpen(false)}
                className="text-2xl font-cinzel tracking-widest text-ivory hover:text-gold"
              >
                {item.title}
              </Link>
            ))}
          </motion.div>
        )}
      </AnimatePresence>
    </nav>
  );
};

export default Navbar;
